% vorbereitung
% G(s) = 1/1+sRC

% a)
f_grenz = 10e3;

R = 10e3;
C = 1 / (2 * pi * f_grenz * R);

grenzen = {2*pi*10, 2*pi*1e6}; % Geschweifte Klammer für Intervall

num = [1];
denum = [R*C, 1];

G = tf(num, denum) %[output:989d2dc6]
% b)
close;

bodeOpts = bodeoptions;
bodeOpts.FreqUnits = 'Hz';
bodeOpts.Grid = 'on';   

f = figure; %[output:640b5e21]
bodeplot(G, grenzen, bodeOpts) %[output:640b5e21]
title("RC-Tiefpass erster Ordnung") %[output:640b5e21]
exportgraphics(f, "./images/lab1_2_0.png", "Resolution",300); %[output:640b5e21]
% c)
f = figure; %[output:8704eb5d]
npOpts = nyquistoptions;
nyquistplot(G, npOpts) %[output:8704eb5d]
title("Nyquist Diagram (Ellipse)") %[output:8704eb5d]
exportgraphics(f, "./images/lab1_2_1.png", "Resolution",300); %[output:8704eb5d]
f = figure; %[output:7f4ca4db]
npOpts = nyquistoptions;
nyquistplot(G, npOpts) %[output:7f4ca4db]
axis equal;  % <-- %[output:7f4ca4db]
title("Nyquist Diagram (Kreis)") %[output:7f4ca4db]
exportgraphics(f, "./images/lab1_2_2.png", "Resolution",300); %[output:7f4ca4db]
% d)
f = figure; %[output:70a1330d]
npOpts.ShowFullContour = 'off';        % exclude negative frequencies
nyquistplot(G, npOpts) %[output:70a1330d]
axis equal;  %[output:70a1330d]
title("Nyquist Diagram (Halbkreis)") %[output:70a1330d]
exportgraphics(f, "./images/lab1_2_3.png", "Resolution",300); %[output:70a1330d]

